var ctrlNik = Runner.getControl(pageid, 'nik');
var ctrlPencarian = Runner.getControl(pageid, 'pencarian');

var delayTimer;

// fungsi validasi NIK (16 digit angka)
function isValidNIK(nik) {
    return /^[0-9]{16}$/.test(nik);
}

// fungsi utama cek pasien
function cekPasien() {
    var nik = ctrlNik.getValue().trim();

    // kosong
    if(nik === "") {
        ctrlPencarian.setValue("");
        return;
    }

    // validasi panjang
    if(nik.length < 16) {
        ctrlPencarian.setValue("NIK belum lengakap (16 digit)");
        return;
    }

    // validasi format angka
    if(!isValidNIK(nik)) {
        ctrlPencarian.setValue("NIK harus 16 digit angka");
        return;
    }

    // loading
    ctrlPencarian.setValue("cek data...");

    $.ajax({
        url: "cek_pasien.php",
        type: "POST",
        data: { nik: nik },
        success: function(res) {
            try {
                var data = JSON.parse(res);

                if(data.status == "ada") {
                   ctrlPencarian.setValue("pasien ini terdaftar dengan alamat gampong : " + data.gampong + ", silahkan isi kolom gampong sesuai data terbaru");
                } else {
                    ctrlPencarian.setValue("pasien ini terdaftar silahkan tambah pasien baru");
                }
            } catch(e) {
                ctrlPencarian.setValue("error parsing data");
                console.log("ERROR PARSE:", e, res);
            }
        },
        error: function(xhr, status, error) {
            ctrlPencarian.setValue("error koneksi ke server");
            console.log("AJAX ERROR:", error);
        }
    });
}

// 🔥 EVENT KEYUP + DELAY (ANTI SPAM)
ctrlNik.on('keyup', function() {
    clearTimeout(delayTimer);

    delayTimer = setTimeout(function() {
        cekPasien();
    }, 500); // delay 0.5 detik
});

// 🔥 EVENT CHANGE (PASTE / AUTOFILL)
ctrlNik.on('change', function() {
    cekPasien();
});

